/* wms-report-IbOrderReportNew.xml - selectIbOrderSql - 입고현황 - 주문별 현황 */ WITH EXPCT AS ( /* 입고예정: IB_HD + IB_DT + IC */ SELECT HD.CTKEY, HD.OWKEY, SUBSTR(HD.IBEXPCTDATE, 1, 8) AS IBEXPCTDATE, HD.IBHDTYPECD, HD.IBHDKEY /* 모SKU: 일반상품 + 아소트 모상품 (UPRIBDTKEY IS NULL) */ , SUM(CASE WHEN DT.UPRIBDTKEY IS NULL AND DT.EXPCTQTY > 0 THEN 1 ELSE 0 END) AS MO_SKU /* 자SKU: 아소트 모상품인 경우 ASRT 마스터에서 예정 자상품 수 조회 */ , SUM(CASE WHEN DT.UPRIBDTKEY IS NULL AND DT.ASRTWKTGTYN = 'Y' THEN (SELECT COUNT(DISTINCT ASRTDTICKEY) FROM TWORK_MST_ASRT WHERE CTKEY = DT.CTKEY AND OWKEY = DT.OWKEY AND ASRTMASICKEY = DT.ICKEY) ELSE 0 END) AS JA_SKU /* 예정EA: 일반상품 + 모상품만 (자상품 제외하여 중복 방지) */ , SUM(CASE WHEN DT.UPRIBDTKEY IS NULL THEN DT.EXPCTQTY ELSE 0 END) AS EXPCTQTY , SUM(CASE WHEN DT.UPRIBDTKEY IS NULL THEN DT.EXPCTQTY * COALESCE(IC.SLPRC, 0) ELSE 0 END) AS EXPCTAMT FROM TWORK_INFO_IB_HD HD INNER JOIN TWORK_INFO_IB_DT DT ON HD.CTKEY = DT.CTKEY AND HD.OWKEY = DT.OWKEY AND HD.IBHDKEY = DT.IBHDKEY INNER JOIN TWORK_MST_IC IC ON DT.CTKEY = IC.CTKEY AND DT.OWKEY = IC.OWKEY AND DT.ICKEY = IC.ICKEY WHERE HD.CTKEY = #{ctkey} AND HD.OWKEY = #{owkey}
AND HD.IBEXPCTDATE BETWEEN #{ibexpctdateFrom} || '000000' AND #{ibexpctdateTo} || '235959'
AND HD.IBHDTYPECD = #{ibhdtypecd}
AND HD.IBSTATUSCD = #{ibstatuscd}
AND HD.IBHDKEY = #{ibhdkey}
GROUP BY HD.CTKEY, HD.OWKEY, SUBSTR(HD.IBEXPCTDATE, 1, 8), HD.IBHDTYPECD, HD.IBHDKEY ), IBCF AS ( /* 입하(입고): IB_DT 기준 IBQTY 집계 */ SELECT DT.CTKEY, DT.OWKEY, DT.IBHDKEY /* 모SKU: 일반상품 + 아소트 모상품 (UPRIBDTKEY IS NULL, IBQTY > 0) */ , SUM(CASE WHEN DT.UPRIBDTKEY IS NULL AND DT.IBQTY > 0 THEN 1 ELSE 0 END) AS MO_SKU /* 자SKU: 아소트 자상품 (UPRIBDTKEY IS NOT NULL, IBQTY > 0) */ , SUM(CASE WHEN DT.UPRIBDTKEY IS NOT NULL AND DT.IBQTY > 0 THEN 1 ELSE 0 END) AS JA_SKU /* 입하EA: 일반상품 + 모상품만 (자상품 제외하여 중복 방지) */ , SUM(CASE WHEN DT.UPRIBDTKEY IS NULL THEN DT.IBQTY ELSE 0 END) AS IBQTY , SUM(CASE WHEN DT.UPRIBDTKEY IS NULL THEN DT.IBQTY * COALESCE(IC.SLPRC, 0) ELSE 0 END) AS IBAMT FROM TWORK_INFO_IB_DT DT INNER JOIN TWORK_MST_IC IC ON DT.CTKEY = IC.CTKEY AND DT.OWKEY = IC.OWKEY AND DT.ICKEY = IC.ICKEY WHERE DT.CTKEY = #{ctkey} AND DT.OWKEY = #{owkey} GROUP BY DT.CTKEY, DT.OWKEY, DT.IBHDKEY ), PLCM AS ( /* 적치: PLCM_DT → IBCF_CNTR → IBCF_DT → IB_DT + IC */ SELECT P.CTKEY, P.OWKEY, P.IBHDKEY /* 모SKU: 일반상품 + 아소트 모상품 (UPRIBDTKEY IS NULL) */ , SUM(CASE WHEN DT.UPRIBDTKEY IS NULL AND P.CNFRMQTY > 0 THEN 1 ELSE 0 END) AS MO_SKU /* 자SKU: 아소트 자상품 (UPRIBDTKEY IS NOT NULL) */ , SUM(CASE WHEN DT.UPRIBDTKEY IS NOT NULL AND P.CNFRMQTY > 0 THEN 1 ELSE 0 END) AS JA_SKU /* 적치EA: 일반상품 + 자상품만 (모상품 제외하여 중복 방지) */ , SUM(CASE WHEN DT.UPRIBDTKEY IS NULL AND DT.ASRTWKTGTYN = 'Y' THEN 0 ELSE P.CNFRMQTY END) AS CNFRMQTY , SUM(CASE WHEN DT.UPRIBDTKEY IS NULL AND DT.ASRTWKTGTYN = 'Y' THEN 0 ELSE P.CNFRMQTY * COALESCE(IC.SLPRC, 0) END) AS CNFRMAMT FROM TWORK_INFO_IB_PLCM_DT P INNER JOIN TWORK_INFO_IBCF_CNTR CF ON P.CTKEY = CF.CTKEY AND P.OWKEY = CF.OWKEY AND P.IBHDKEY = CF.IBHDKEY AND P.IBDTKEY = CF.IBDTKEY AND P.IBCFSEQNO = CF.IBCFSEQNO AND P.CNTRNO = CF.CNTRNO AND P.ICKEY = CF.ICKEY INNER JOIN TWORK_INFO_IBCF_DT CFD ON CF.CTKEY = CFD.CTKEY AND CF.OWKEY = CFD.OWKEY AND CF.IBHDKEY = CFD.IBHDKEY AND CF.IBDTKEY = CFD.IBDTKEY AND CF.IBCFSEQNO = CFD.IBCFSEQNO INNER JOIN TWORK_INFO_IB_DT DT ON CFD.CTKEY = DT.CTKEY AND CFD.OWKEY = DT.OWKEY AND CFD.IBHDKEY = DT.IBHDKEY AND CFD.IBDTKEY = DT.IBDTKEY INNER JOIN TWORK_MST_IC IC ON DT.CTKEY = IC.CTKEY AND DT.OWKEY = IC.OWKEY AND DT.ICKEY = IC.ICKEY WHERE P.CTKEY = #{ctkey} AND P.OWKEY = #{owkey} GROUP BY P.CTKEY, P.OWKEY, P.IBHDKEY ) SELECT E.IBEXPCTDATE AS ibexpctdate , E.IBHDTYPECD AS ibtype , (SELECT CTCDDTNM FROM TWORK_MST_CTCD_DT WHERE CTKEY = #{ctkey} AND CTCDHDKEY='IBHDTYPECD' AND CTCDDTKEY = E.IBHDTYPECD LIMIT 1) AS obctnm /* 입고예정 정보 (IB_DT 기준) */ , SUM(E.MO_SKU) AS planskumother , SUM(E.JA_SKU) AS planskuchild , SUM(E.EXPCTQTY) AS planea , SUM(E.EXPCTAMT) AS planamt /* 입하 정보 (IB_DT 기준) */ , COALESCE(SUM(I.MO_SKU), 0) AS inskumother , COALESCE(SUM(I.JA_SKU), 0) AS inskuchild , COALESCE(SUM(I.IBQTY), 0) AS inea , COALESCE(SUM(I.IBAMT), 0) AS inamt /* SKU진척률 = 입하 모SKU / 입고예정 모SKU * 100 */ , CASE WHEN SUM(E.MO_SKU) = 0 THEN 0 ELSE ROUND(COALESCE(SUM(I.MO_SKU), 0) / SUM(E.MO_SKU) * 100, 2) END AS inskurate /* EA진척률 = 입하EA / 입고예정EA * 100 */ , CASE WHEN SUM(E.EXPCTQTY) = 0 THEN 0 ELSE ROUND(COALESCE(SUM(I.IBQTY), 0) / SUM(E.EXPCTQTY) * 100, 2) END AS inearate /* 적치 정보 (PLCM_DT 기준) */ , COALESCE(SUM(P.MO_SKU), 0) AS putskumother , COALESCE(SUM(P.JA_SKU), 0) AS putskuchild , COALESCE(SUM(P.CNFRMQTY), 0) AS putea , COALESCE(SUM(P.CNFRMAMT), 0) AS putamt /* SKU진척률 = 적치 모SKU / 입고예정 모SKU * 100 */ , CASE WHEN SUM(E.MO_SKU) = 0 THEN 0 ELSE ROUND(COALESCE(SUM(P.MO_SKU), 0) / SUM(E.MO_SKU) * 100, 2) END AS putskurate /* EA진척률 = 적치EA / 입고예정EA * 100 */ , CASE WHEN SUM(E.EXPCTQTY) = 0 THEN 0 ELSE ROUND(COALESCE(SUM(P.CNFRMQTY), 0) / SUM(E.EXPCTQTY) * 100, 2) END AS putearate FROM EXPCT E LEFT JOIN IBCF I ON E.CTKEY = I.CTKEY AND E.OWKEY = I.OWKEY AND E.IBHDKEY = I.IBHDKEY LEFT JOIN PLCM P ON E.CTKEY = P.CTKEY AND E.OWKEY = P.OWKEY AND E.IBHDKEY = P.IBHDKEY GROUP BY E.IBEXPCTDATE, E.IBHDTYPECD

