/* wms-report-IbOrderReportNew.xml - selectAsrtOrderDetailSql - 아소트 상세 */ WITH BASE AS ( SELECT HD.CTKEY , HD.OWKEY , HD.IBHDKEY , HD.IBHDTYPECD AS IBTYPE , SUBSTR(HD.IBEXPCTDATE,1,8) AS IBEXPCTDATE , HD.IBSTATUSCD , HD.FRCTKEY , DT.IBDTKEY , COALESCE(DT.EXPCTQTY, 0) AS EXPCTQTY , COALESCE(DT.ASRTWKQTY, 0) AS ASRTWKQTY , DT.ASRTWKTGTYN , DT.UPRIBDTKEY , COALESCE(IC.SLPRC, 0) AS SLPRC /* 모상품인 경우 아소트 마스터에서 예정 자상품 SKU 수 */ , CASE WHEN DT.ASRTWKTGTYN = 'Y' THEN (SELECT COUNT(DISTINCT ASRTDTICKEY) FROM TWORK_MST_ASRT WHERE CTKEY = DT.CTKEY AND OWKEY = DT.OWKEY AND ASRTMASICKEY = DT.ICKEY) ELSE 0 END AS PLAN_JA_CNT FROM TWORK_INFO_IB_HD HD JOIN TWORK_INFO_IB_DT DT ON HD.CTKEY = DT.CTKEY AND HD.OWKEY = DT.OWKEY AND HD.IBHDKEY = DT.IBHDKEY JOIN TWORK_MST_IC IC ON DT.CTKEY = IC.CTKEY AND DT.OWKEY = IC.OWKEY AND DT.ICKEY = IC.ICKEY WHERE HD.CTKEY = #{ctkey} AND HD.OWKEY = #{owkey} AND (DT.ASRTWKTGTYN = 'Y' OR DT.UPRIBDTKEY IS NOT NULL)
AND HD.IBEXPCTDATE BETWEEN #{ibexpctdate} || '000000' AND #{ibexpctdate} || '235959'
AND HD.IBHDTYPECD = #{ibhdtypecd}
AND HD.IBSTATUSCD = #{ibstatuscd}
), PLCM AS ( /* 적치: 자상품(UPRIBDTKEY IS NOT NULL)만 */ SELECT P.CTKEY , P.OWKEY , P.IBHDKEY , P.IBDTKEY , SUM(COALESCE(P.CNFRMQTY, 0)) AS PLCM_QTY FROM TWORK_INFO_IB_PLCM_DT P JOIN TWORK_INFO_IBCF_CNTR CF ON P.CTKEY = CF.CTKEY AND P.OWKEY = CF.OWKEY AND P.IBHDKEY = CF.IBHDKEY AND P.IBDTKEY = CF.IBDTKEY AND P.IBCFSEQNO = CF.IBCFSEQNO AND P.CNTRNO = CF.CNTRNO AND P.ICKEY = CF.ICKEY JOIN TWORK_INFO_IBCF_DT CFD ON CF.CTKEY = CFD.CTKEY AND CF.OWKEY = CFD.OWKEY AND CF.IBHDKEY = CFD.IBHDKEY AND CF.IBDTKEY = CFD.IBDTKEY AND CF.IBCFSEQNO = CFD.IBCFSEQNO JOIN TWORK_INFO_IB_DT DT ON CFD.CTKEY = DT.CTKEY AND CFD.OWKEY = DT.OWKEY AND CFD.IBHDKEY = DT.IBHDKEY AND CFD.IBDTKEY = DT.IBDTKEY WHERE DT.UPRIBDTKEY IS NOT NULL GROUP BY P.CTKEY, P.OWKEY, P.IBHDKEY, P.IBDTKEY ) SELECT ROW_NUMBER() OVER(ORDER BY B.IBEXPCTDATE, B.IBTYPE, B.IBHDKEY) AS no , B.IBTYPE AS ibtype , (SELECT CTCDDTNM FROM TWORK_MST_CTCD_DT WHERE CTKEY = #{ctkey} AND CTCDHDKEY='IBHDTYPECD' AND CTCDDTKEY = B.IBTYPE LIMIT 1) AS ibtypename , B.IBEXPCTDATE AS ibexpctdate , B.IBSTATUSCD AS ibstatus , (SELECT CTCDDTNM FROM TWORK_MST_CTCD_DT WHERE CTKEY = #{ctkey} AND CTCDHDKEY='IBSTATUSCD' AND CTCDDTKEY = B.IBSTATUSCD LIMIT 1) AS ibstatusname , (SELECT CTNM FROM TWORK_MST_CT WHERE CTKEY = B.FRCTKEY) AS frctname , B.IBHDKEY AS ibhdkey /* 입고예정 정보: 아소트 대상 모상품/생성 예정 자상품 */ , SUM(CASE WHEN B.UPRIBDTKEY IS NULL AND B.ASRTWKTGTYN = 'Y' THEN 1 ELSE 0 END) AS planmosku , SUM(B.PLAN_JA_CNT) AS planjasku , SUM(CASE WHEN B.UPRIBDTKEY IS NULL AND B.ASRTWKTGTYN = 'Y' THEN B.EXPCTQTY ELSE 0 END) AS planea , SUM(CASE WHEN B.UPRIBDTKEY IS NULL AND B.ASRTWKTGTYN = 'Y' THEN B.EXPCTQTY * B.SLPRC ELSE 0 END) AS planamt /* 아소트 작업: 모상품 수, 생성된 자상품 */ , SUM(CASE WHEN B.UPRIBDTKEY IS NULL AND B.ASRTWKTGTYN = 'Y' AND B.ASRTWKQTY > 0 THEN 1 ELSE 0 END) AS workmosku , SUM(CASE WHEN B.UPRIBDTKEY IS NOT NULL AND B.ASRTWKQTY > 0 THEN 1 ELSE 0 END) AS workjasku , SUM(CASE WHEN B.UPRIBDTKEY IS NULL AND B.ASRTWKQTY > 0 THEN B.ASRTWKQTY ELSE 0 END) AS workea , SUM(CASE WHEN B.UPRIBDTKEY IS NOT NULL AND B.ASRTWKQTY > 0 THEN B.ASRTWKQTY * B.SLPRC ELSE 0 END) AS workamt /* SKU 진척률 = 생성된 모상품 / 예정 모상품 * 100 */ , CASE WHEN SUM(CASE WHEN B.UPRIBDTKEY IS NULL AND B.ASRTWKTGTYN = 'Y' THEN 1 ELSE 0 END) = 0 THEN 0 ELSE ROUND(SUM(CASE WHEN B.UPRIBDTKEY IS NULL AND B.ASRTWKTGTYN = 'Y' AND B.ASRTWKQTY > 0 THEN 1 ELSE 0 END) / SUM(CASE WHEN B.UPRIBDTKEY IS NULL AND B.ASRTWKTGTYN = 'Y' THEN 1 ELSE 0 END) * 100, 2) END AS workskurate /* EA 진척률 = 생성된 모상품 EA / 모상품 예정EA * 100 */ , CASE WHEN SUM(CASE WHEN B.UPRIBDTKEY IS NULL AND B.ASRTWKTGTYN = 'Y' THEN B.EXPCTQTY ELSE 0 END) = 0 THEN 0 ELSE ROUND(SUM(CASE WHEN B.UPRIBDTKEY IS NULL AND B.ASRTWKTGTYN = 'Y' THEN B.ASRTWKQTY ELSE 0 END) / SUM(CASE WHEN B.UPRIBDTKEY IS NULL AND B.ASRTWKTGTYN = 'Y' THEN B.EXPCTQTY ELSE 0 END) * 100, 2) END AS workearate /* 아소트 적치: 자상품 적치 */ , SUM(CASE WHEN B.UPRIBDTKEY IS NOT NULL AND COALESCE(P.PLCM_QTY, 0) > 0 THEN 1 ELSE 0 END) AS putjasku , SUM(CASE WHEN B.UPRIBDTKEY IS NOT NULL THEN COALESCE(P.PLCM_QTY, 0) ELSE 0 END) AS putea , SUM(CASE WHEN B.UPRIBDTKEY IS NOT NULL THEN COALESCE(P.PLCM_QTY, 0) * B.SLPRC ELSE 0 END) AS putamt /* 적치 SKU 진척률 = 적치된 자상품 / 생성된 자상품 * 100 */ , CASE WHEN SUM(CASE WHEN B.UPRIBDTKEY IS NOT NULL THEN 1 ELSE 0 END) = 0 THEN 0 ELSE ROUND(SUM(CASE WHEN B.UPRIBDTKEY IS NOT NULL AND COALESCE(P.PLCM_QTY, 0) > 0 THEN 1 ELSE 0 END) / SUM(CASE WHEN B.UPRIBDTKEY IS NOT NULL THEN 1 ELSE 0 END) * 100, 2) END AS putskurate /* 적치 EA 진척률 = 적치EA / 생성된 자상품 EA * 100 */ , CASE WHEN SUM(CASE WHEN B.UPRIBDTKEY IS NOT NULL THEN B.ASRTWKQTY ELSE 0 END) = 0 THEN 0 ELSE ROUND(SUM(CASE WHEN B.UPRIBDTKEY IS NOT NULL THEN COALESCE(P.PLCM_QTY, 0) ELSE 0 END) / SUM(CASE WHEN B.UPRIBDTKEY IS NOT NULL THEN B.ASRTWKQTY ELSE 0 END) * 100, 2) END AS putearate FROM BASE B LEFT JOIN PLCM P ON B.CTKEY = P.CTKEY AND B.OWKEY = P.OWKEY AND B.IBHDKEY = P.IBHDKEY AND B.IBDTKEY = P.IBDTKEY GROUP BY B.IBTYPE, B.IBEXPCTDATE, B.IBSTATUSCD, B.FRCTKEY, B.IBHDKEY

