mapper.sql:
/* wms-report-IbOrderReportNew.xml - selectIbDetailSql - 상세현황 - 존/구역별 */ /* TWORK_MST_AR의 P/H 모든 구역을 기준으로 펼쳐서 각 구역별 입고 진척율 표시 */ /* IC.LCKEY가 NULL이거나 LC 매핑이 안 되거나 P/H존이 아니면 '-' 행으로 집계 */ WITH AR_BASE AS ( /* P/H 존의 모든 구역 목록 + 미매핑용 '-' 행 */ SELECT ZNKEY, ARKEY FROM TWORK_MST_AR WHERE CTKEY = #{ctkey} AND ZNKEY IN ('P', 'H') UNION ALL SELECT '-' AS ZNKEY, '-' AS ARKEY ), EXPCT AS ( /* 입고예정: IB_DT + IC + LC(대표로케이션) - 구역별 집계 */ SELECT CASE WHEN IC.LCKEY IS NOT NULL AND L.LCKEY IS NOT NULL AND L.ZNKEY IN ('P', 'H') THEN L.ZNKEY ELSE '-' END AS ZNKEY , CASE WHEN IC.LCKEY IS NOT NULL AND L.LCKEY IS NOT NULL AND L.ZNKEY IN ('P', 'H') THEN L.ARKEY ELSE '-' END AS ARKEY /* 모SKU: 일반상품 + 아소트 모상품 (UPRIBDTKEY IS NULL) */ , SUM(CASE WHEN DT.UPRIBDTKEY IS NULL AND DT.EXPCTQTY > 0 THEN 1 ELSE 0 END) AS MO_SKU /* 자SKU: 아소트 모상품인 경우 ASRT 마스터에서 예정 자상품 수 조회 */ , SUM(CASE WHEN DT.UPRIBDTKEY IS NULL AND DT.ASRTWKTGTYN = 'Y' THEN (SELECT COUNT(DISTINCT ASRTDTICKEY) FROM TWORK_MST_ASRT WHERE CTKEY = DT.CTKEY AND OWKEY = DT.OWKEY AND ASRTMASICKEY = DT.ICKEY) ELSE 0 END) AS JA_SKU /* 예정EA: 일반상품 + 모상품만 (자상품 제외하여 중복 방지) */ , SUM(CASE WHEN DT.UPRIBDTKEY IS NULL THEN DT.EXPCTQTY ELSE 0 END) AS EXPCTQTY , SUM(CASE WHEN DT.UPRIBDTKEY IS NULL THEN DT.EXPCTQTY * COALESCE(IC.SLPRC, 0) ELSE 0 END) AS EXPCTAMT FROM TWORK_INFO_IB_DT DT INNER JOIN TWORK_MST_IC IC ON DT.CTKEY = IC.CTKEY AND DT.OWKEY = IC.OWKEY AND DT.ICKEY = IC.ICKEY LEFT JOIN TWORK_MST_LC L ON IC.CTKEY = L.CTKEY AND IC.LCKEY = L.LCKEY /* 상품 마스터의 대표 로케이션 (LEFT JOIN) */ INNER JOIN TWORK_INFO_IB_HD HD ON DT.CTKEY = HD.CTKEY AND DT.OWKEY = HD.OWKEY AND DT.IBHDKEY = HD.IBHDKEY WHERE DT.CTKEY = #{ctkey} AND DT.OWKEY = #{owkey}
AND HD.IBEXPCTDATE BETWEEN #{ibexpctdateFrom} || '000000' AND #{ibexpctdateTo} || '235959'
AND HD.IBHDTYPECD = #{ibhdtypecd}
GROUP BY CASE WHEN IC.LCKEY IS NOT NULL AND L.LCKEY IS NOT NULL AND L.ZNKEY IN ('P', 'H') THEN L.ZNKEY ELSE '-' END , CASE WHEN IC.LCKEY IS NOT NULL AND L.LCKEY IS NOT NULL AND L.ZNKEY IN ('P', 'H') THEN L.ARKEY ELSE '-' END ), IBCF AS ( /* 입하(입고): IB_DT + IC + LC(대표로케이션) 기준 IBQTY 집계 */ SELECT CASE WHEN IC.LCKEY IS NOT NULL AND L.LCKEY IS NOT NULL AND L.ZNKEY IN ('P', 'H') THEN L.ZNKEY ELSE '-' END AS ZNKEY , CASE WHEN IC.LCKEY IS NOT NULL AND L.LCKEY IS NOT NULL AND L.ZNKEY IN ('P', 'H') THEN L.ARKEY ELSE '-' END AS ARKEY /* 모SKU: 일반상품 + 아소트 모상품 (UPRIBDTKEY IS NULL, IBQTY > 0) */ , SUM(CASE WHEN DT.UPRIBDTKEY IS NULL AND DT.IBQTY > 0 THEN 1 ELSE 0 END) AS MO_SKU /* 자SKU: 아소트 자상품 (UPRIBDTKEY IS NOT NULL, IBQTY > 0) */ , SUM(CASE WHEN DT.UPRIBDTKEY IS NOT NULL AND DT.IBQTY > 0 THEN 1 ELSE 0 END) AS JA_SKU /* 입하EA: 일반상품 + 모상품만 (자상품 제외하여 중복 방지) */ , SUM(CASE WHEN DT.UPRIBDTKEY IS NULL THEN DT.IBQTY ELSE 0 END) AS IBQTY , SUM(CASE WHEN DT.UPRIBDTKEY IS NULL THEN DT.IBQTY * COALESCE(IC.SLPRC, 0) ELSE 0 END) AS IBAMT FROM TWORK_INFO_IB_DT DT INNER JOIN TWORK_MST_IC IC ON DT.CTKEY = IC.CTKEY AND DT.OWKEY = IC.OWKEY AND DT.ICKEY = IC.ICKEY LEFT JOIN TWORK_MST_LC L ON IC.CTKEY = L.CTKEY AND IC.LCKEY = L.LCKEY /* 상품 마스터의 대표 로케이션 (LEFT JOIN) */ INNER JOIN TWORK_INFO_IB_HD HD ON DT.CTKEY = HD.CTKEY AND DT.OWKEY = HD.OWKEY AND DT.IBHDKEY = HD.IBHDKEY WHERE DT.CTKEY = #{ctkey} AND DT.OWKEY = #{owkey}
AND HD.IBEXPCTDATE BETWEEN #{ibexpctdateFrom} || '000000' AND #{ibexpctdateTo} || '235959'
AND HD.IBHDTYPECD = #{ibhdtypecd}
GROUP BY CASE WHEN IC.LCKEY IS NOT NULL AND L.LCKEY IS NOT NULL AND L.ZNKEY IN ('P', 'H') THEN L.ZNKEY ELSE '-' END , CASE WHEN IC.LCKEY IS NOT NULL AND L.LCKEY IS NOT NULL AND L.ZNKEY IN ('P', 'H') THEN L.ARKEY ELSE '-' END ), PLCM AS ( /* 적치: PLCM_DT → IBCF_CNTR → IBCF_DT → IB_DT + IC + LC(대표로케이션) */ SELECT CASE WHEN IC.LCKEY IS NOT NULL AND L.LCKEY IS NOT NULL AND L.ZNKEY IN ('P', 'H') THEN L.ZNKEY ELSE '-' END AS ZNKEY , CASE WHEN IC.LCKEY IS NOT NULL AND L.LCKEY IS NOT NULL AND L.ZNKEY IN ('P', 'H') THEN L.ARKEY ELSE '-' END AS ARKEY /* 모SKU: 일반상품 + 아소트 모상품 (UPRIBDTKEY IS NULL) */ , SUM(CASE WHEN DT.UPRIBDTKEY IS NULL AND P.CNFRMQTY > 0 THEN 1 ELSE 0 END) AS MO_SKU /* 자SKU: 아소트 자상품 (UPRIBDTKEY IS NOT NULL) */ , SUM(CASE WHEN DT.UPRIBDTKEY IS NOT NULL AND P.CNFRMQTY > 0 THEN 1 ELSE 0 END) AS JA_SKU /* 적치EA: 일반상품 + 자상품만 (모상품이 아소트 대상이면 제외) */ , SUM(CASE WHEN DT.UPRIBDTKEY IS NULL AND DT.ASRTWKTGTYN = 'Y' THEN 0 ELSE P.CNFRMQTY END) AS CNFRMQTY , SUM(CASE WHEN DT.UPRIBDTKEY IS NULL AND DT.ASRTWKTGTYN = 'Y' THEN 0 ELSE P.CNFRMQTY * COALESCE(IC.SLPRC, 0) END) AS CNFRMAMT FROM TWORK_INFO_IB_PLCM_DT P INNER JOIN TWORK_INFO_IBCF_CNTR CF ON P.CTKEY = CF.CTKEY AND P.OWKEY = CF.OWKEY AND P.IBHDKEY = CF.IBHDKEY AND P.IBDTKEY = CF.IBDTKEY AND P.IBCFSEQNO = CF.IBCFSEQNO AND P.CNTRNO = CF.CNTRNO AND P.ICKEY = CF.ICKEY INNER JOIN TWORK_INFO_IBCF_DT CFD ON CF.CTKEY = CFD.CTKEY AND CF.OWKEY = CFD.OWKEY AND CF.IBHDKEY = CFD.IBHDKEY AND CF.IBDTKEY = CFD.IBDTKEY AND CF.IBCFSEQNO = CFD.IBCFSEQNO INNER JOIN TWORK_INFO_IB_DT DT ON CFD.CTKEY = DT.CTKEY AND CFD.OWKEY = DT.OWKEY AND CFD.IBHDKEY = DT.IBHDKEY AND CFD.IBDTKEY = DT.IBDTKEY INNER JOIN TWORK_MST_IC IC ON DT.CTKEY = IC.CTKEY AND DT.OWKEY = IC.OWKEY AND DT.ICKEY = IC.ICKEY LEFT JOIN TWORK_MST_LC L ON IC.CTKEY = L.CTKEY AND IC.LCKEY = L.LCKEY /* 상품 마스터의 대표 로케이션 (LEFT JOIN) */ INNER JOIN TWORK_INFO_IB_HD HD ON DT.CTKEY = HD.CTKEY AND DT.OWKEY = HD.OWKEY AND DT.IBHDKEY = HD.IBHDKEY WHERE P.CTKEY = #{ctkey} AND P.OWKEY = #{owkey}
AND HD.IBEXPCTDATE BETWEEN #{ibexpctdateFrom} || '000000' AND #{ibexpctdateTo} || '235959'
AND HD.IBHDTYPECD = #{ibhdtypecd}
GROUP BY CASE WHEN IC.LCKEY IS NOT NULL AND L.LCKEY IS NOT NULL AND L.ZNKEY IN ('P', 'H') THEN L.ZNKEY ELSE '-' END , CASE WHEN IC.LCKEY IS NOT NULL AND L.LCKEY IS NOT NULL AND L.ZNKEY IN ('P', 'H') THEN L.ARKEY ELSE '-' END ) SELECT #{ibexpctdateFrom} AS ibexpctdate , B.ZNKEY AS znkey , B.ARKEY AS arkey /* 입고예정 정보 */ , COALESCE(E.MO_SKU, 0) AS expctmascnt , COALESCE(E.JA_SKU, 0) AS expctdtcnt , COALESCE(E.EXPCTQTY, 0) AS expctqty , COALESCE(E.EXPCTAMT, 0) AS expslprc /* 입하 정보 */ , COALESCE(I.MO_SKU, 0) AS ibmascnt , COALESCE(I.JA_SKU, 0) AS ibdtcnt , COALESCE(I.IBQTY, 0) AS ibqty , COALESCE(I.IBAMT, 0) AS ibslprc /* SKU진척률 = 입하 모SKU / 입고예정 모SKU * 100 */ , CASE WHEN COALESCE(E.MO_SKU, 0) = 0 THEN 0 ELSE ROUND(COALESCE(I.MO_SKU, 0) / E.MO_SKU * 100, 1) END AS ibskuprc /* EA진척률 = 입하EA / 입고예정EA * 100 */ , CASE WHEN COALESCE(E.EXPCTQTY, 0) = 0 THEN 0 ELSE ROUND(COALESCE(I.IBQTY, 0) / E.EXPCTQTY * 100, 1) END AS ibeaprc /* 적치 정보 */ , COALESCE(P.MO_SKU, 0) AS cnfrmmascnt , COALESCE(P.JA_SKU, 0) AS cnfrmdtcnt , COALESCE(P.CNFRMQTY, 0) AS cnfrmqty , COALESCE(P.CNFRMAMT, 0) AS cnfrmslprc /* SKU진척률 = 적치 모SKU / 입고예정 모SKU * 100 */ , CASE WHEN COALESCE(E.MO_SKU, 0) = 0 THEN 0 ELSE ROUND(COALESCE(P.MO_SKU, 0) / E.MO_SKU * 100, 1) END AS cnfrmskuprc /* EA진척률 = 적치EA / 입고예정EA * 100 */ , CASE WHEN COALESCE(E.EXPCTQTY, 0) = 0 THEN 0 ELSE ROUND(COALESCE(P.CNFRMQTY, 0) / E.EXPCTQTY * 100, 1) END AS cnfrmeaprc FROM AR_BASE B LEFT JOIN EXPCT E ON B.ZNKEY = E.ZNKEY AND B.ARKEY = E.ARKEY LEFT JOIN IBCF I ON B.ZNKEY = I.ZNKEY AND B.ARKEY = I.ARKEY LEFT JOIN PLCM P ON B.ZNKEY = P.ZNKEY AND B.ARKEY = P.ARKEY

